import { ChatFlowise } from 'flowise';
import { TavilySearchTool } from 'langchain/tools/tavily';

const researchFlow = new ChatFlowise({
  nodes: {
    search: new TavilySearchTool({
      maxResults: 10,
      searchDepth: 'advanced'
    }),
    embedder: new OpenAIEmbeddings(),
    vectorStore: new PineconeStore(),
    llm: new ChatOpenAI({ model: 'gpt-4o-mini' }),
    synthesizer: new LLMChain({
      llm: new ChatOpenAI({ model: 'gpt-4o' }),
      prompt: researchSynthesisPrompt
    })
  },
  edges: [
    { from: 'query', to: 'search' },
    { from: 'search', to: 'embedder' },
    { from: 'embedder', to: 'vectorStore' },
    { from: 'vectorStore', to: 'llm' },
    { from: 'llm', to: 'synthesizer' }
  ]
});

import { AgentExecutor, createReactAgent } from 'langchain/agents';

const supervisor = createReactAgent({
  llm: chatOpenAI,
  tools: [searchTool, factCheckTool, biasDetector],
  prompt: `You are research supervisor. Route to:
- verification_agent for source/claim checks
- analysis_agent for data synthesis
- bias_agent for perspective detection`
});

const verificationAgent = new AgentExecutor({
  agent: createReactAgent({ llm, tools: [sourceVerifier] }),
  tools: [sourceVerifier]
});

class RecencyCheckerTool extends BaseTool {
  name = 'recency_checker';
  description = 'Check if sources are recent (last 6 months)';

  async _call(input: string) {
    const docs = await this.vectorStore.similaritySearch(input);
    return docs.map(doc => ({
      content: doc.pageContent,
      recency: this.checkDate(doc.metadata.date),
      score: this.semanticScore(doc, input)
    }));
  }
}

class BiasDetectorTool extends BaseTool {
  async _call(text: string) {
    const analysis = await this.llm.call([
      new HumanMessage({
        content: `Rate bias in this research text (1-10): ${text}`
      })
    ]);
    return { biasScore: parseFloat(analysis.content), flagged: score > 7 };
  }
}

import { BufferWindowMemory } from 'langchain/memory';

const researchMemory = new BufferWindowMemory({
  k: 20,
  returnMessages: true,
  memoryKey: 'research_chat_history',
  inputKey: 'input',
  outputKey: 'output'
});

const agentWithMemory = new AgentExecutor({
  agent,
  tools,
  memory: researchMemory,
  verbose: true,
  maxIterations: 5
});

// Persist verification metadata
researchMemory.chatHistory.addMessages([
  new SystemMessage('Preserve all source URLs and verification status')
]);

