import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  apiKey: process.env.VEX_API_KEY,
  project: 'flowise-research-agent'
});

const flowiseConfig = {
  callbacks: [{
    type: 'afterLLM',
    callback: async (output, metadata) => {
      const verified = await vex.verify({
        text: output,
        useCase: 'research_agent',
        checks: ['source_verification', 'claim_accuracy']
      });
      if (!verified.pass) {
        throw new Error(`Vex blocked: ${verified.issues.join(', ')}`);
      }
      return { ...output, vexMetadata: verified };
    }
  }]
};

const retrievalCallback = async (retrievedDocs, query) => {
  const results = await vex.verify({
    text: retrievedDocs.map(d => d.pageContent).join('\n'),
    context: { query },
    useCase: 'rag_retrieval',
    checks: ['semantic_relevance', 'recency_check'],
    threshold: { relevance: 0.75, recency_days: 180 }
  });

  if (results.score.relevance < 0.75) {
    console.warn('Low relevance docs filtered:', results.flagged_docs);
    return retrievedDocs.filter(doc => results.passed_docs.includes(doc.id));
  }

  return retrievedDocs;
};

// Attach to vector store node
vectorStoreRetriever.callbackManager = {
  handleRetrieverEnd: retrievalCallback
};

const handoffGuardrail = async (input, agentName, context) => {
  const preserved = await vex.preserveContext({
    currentInput: input,
    agent: agentName,
    priorContext: context,
    useCase: 'multi_agent_handoff',
    checks: ['context_loss_detection', 'bias_propagation']
  });

  return {
    ...input,
    vexContext: preserved.metadata,
    sourceTrail: preserved.verifiedSources,
    warning: preserved.biasDetected ? 'Review for bias' : null
  };
};

// Global supervisor hook
supervisor.beforeAgentExecution = handoffGuardrail;

// Research memory integration
researchMemory.saveContext = async (input, output) => {
  const verified = await vex.verify({ text: output });
  await researchMemory.saveContext(input, verified.output);
};
